import{_ as t,o,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"61. Personal Sick Carer S Leave","description":"","frontmatter":{"title":"61. Personal Sick Carer S Leave","eba":"Doctors in Training 2022-2026","topics":["leave","personal-leave","preliminary"]},"headers":[],"relativePath":"ebas/doctors-in-training/leave/61-personal-sick-carer-s-leave.md","filePath":"ebas/doctors-in-training/leave/61-personal-sick-carer-s-leave.md"}'),n={name:"ebas/doctors-in-training/leave/61-personal-sick-carer-s-leave.md"};function s(i,e,c,p,l,h){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_61-personal-sick-carer-s-leave" tabindex="-1">61. Personal Sick Carer S Leave <a class="header-anchor" href="#_61-personal-sick-carer-s-leave" aria-label="Permalink to &quot;61. Personal Sick Carer S Leave&quot;">​</a></h1><p><strong>61.1</strong> Entitlement</p><p><strong>(a)</strong> Paid personal/carer’s leave will be available to a Doctor when they are absent because of:</p><p><strong>(i)</strong> personal illness or injury;</p><p><strong>(ii)</strong> personal illness or injury of an immediate family or household member who requires the Doctor&#39;s care or support;</p><p><strong>(iii)</strong> an unexpected emergency affecting an immediate family or household member who requires the Doctor&#39;s care or support; or</p><p><strong>(iv)</strong> the requirement to provide ongoing care and attention to another person who is wholly or substantially dependent on the Doctor, provided that the care and attention is not wholly or substantially on a commercial basis.</p><p><strong>(b)</strong> A Doctor is entitled to 28 days paid personal/carer’s leave for each year of service. Unused personal/carer’s leave accumulates from year to year.</p><p><strong>(c)</strong> When a Doctor takes personal/carer’s leave during a period of rostered duty, the leave must be paid at the ordinary weekly rate of pay on the basis of the projected roster for a maximum of 14 consecutive days. For all personal/carer’s leave beyond 14 consecutive days the Doctor must be paid at the rate of 7.6 hours per day for HMOs, MOs and SMOs and 8.6 hours per day for Registrars, save that a Doctor will not be paid less than the Doctor’s base rate of pay for the Doctor’s ordinary hours of work in the period of paid personal/carer’s leave.</p><p><strong>61.2</strong> Immediate Family or Household</p><p><strong>(a)</strong> The term immediate family includes:</p><p><strong>(i)</strong> spouse (including a former spouse, a de facto partner and a former de facto partner) of the Doctor. A de facto partner means a person who, although not legally married to the Doctor, lives with the employee in a relationship as a couple on a genuine domestic basis (whether the Doctor and the person are of the same sex or different sexes); and</p><p><strong>(ii)</strong> child or an adult child (including an adopted child, a step child or an ex- nuptial child), parent, grandparent, grandchild or sibling of the Doctor or spouse of the Doctor.</p><p><strong>61.3</strong> Use of Accumulated Personal/Carer’s Leave</p><p><strong>(a)</strong> A Doctor is entitled to use accumulated personal/carer’s leave for the purposes of this clause where the current year&#39;s personal/carer’s leave entitlement has been exhausted.</p><p><strong>(b)</strong> The Doctor may request the Health Service’s consent to take up to five days’ annual leave in any one year as carer’s leave.</p><p><strong>(c)</strong> The Doctor may request the Health Service’s consent to take time off in lieu of payment for overtime for carer’s leave purposes. One hour of overtime worked is equal to one hour of time off for carer’s leave.</p><p><strong>(d)</strong> The Doctor, on his or her request, must be paid for the overtime worked if the time off in lieu has not been taken as carer’s leave within four weeks of the overtime being accrued.</p><p><strong>(e)</strong> The Doctor may request the Health Service’s consent to work make-up time for carer’s leave purposes. In this case, the Doctor works the same number of ordinary hours taken as carer’s leave during the ordinary spread of hours, but at a later time.</p><p><strong>61.4</strong> Notice and Evidence Requirements – Personal Leave</p><p><strong>(a)</strong> For three single day absences per year, the Doctor will not be required to provide any supporting evidence to substantiate their claim for personal leave. However, to be eligible for payment, the Doctor will be required to notify the Health Service two hours before the start of the shift, or as soon as practicable (which may be the time after the leave has started).</p><p><strong>(b)</strong> For other days absent due to personal illness or injury, the Health Service may require a Doctor to provide evidence of illness as follows:</p><p><strong>(i)</strong> a Medical Certificate from another Doctor, but only in circumstances when the certificate may be properly provided; or</p><p><strong>(ii)</strong> such other reasonable evidence as would satisfy the National Employment Standards (refer s.107 of the Act).</p><p><strong>(c)</strong> Personal/carer’s leave can be used in addition to worker’s compensation payments and Workers Compensation Make-up Pay (refer <a href="/eba/ebas/doctors-in-training/remuneration/45-workers-compensation-make-up-pay.html">clause 45</a>) to make up payments to 100% of the Doctor’s ordinary weekly rate of pay pursuant to <a href="/eba/ebas/doctors-in-training/appendices/2-doctors-in-training-remuneration-allowances-and-deductions.html">Appendix 2</a>, Table 1.1.</p><p><strong>61.5</strong> Notice and Evidence Requirements – Carer’s Leave</p><p><strong>(a)</strong> The Doctor, on the Health Service’s request, must demonstrate the illness or injury of the person concerned by either Medical Certificate or Statutory Declaration.</p><p><strong>(b)</strong> When practical, the Doctor must give the Health Service prior notice of their intended absence due to carer’s leave. If not practical to provide prior notice, the Doctor should, where possible give notice by telephone at the first opportunity on the day of the absence beginning. Notice should otherwise be given in accordance with section 107(2)(a) of the Act.</p><p><strong>(c)</strong> Notice for the purposes of this subclause 61.5 means estimated date of absence, estimated length of absence, the name of the person to be cared for and their relationship to the Doctor.</p><p><strong>61.6</strong> Unpaid Carer&#39;s Leave</p><p>Where a Doctor has exhausted all paid personal/carer’s leave entitlements, he/she is entitled to take unpaid carer’s leave to provide care and support in the circumstances outlined in subclauses 61.1(a)(ii), 61.1(a)(iii) or 61.1(a)(iv). The Health Service and the Doctor will agree on the period. In the absence of agreement the Doctor is entitled to take up to two days&#39; unpaid carer’s leave per occasion.</p><p><strong>61.7</strong> Absence on Public Holidays</p><p>If the period during which a Doctor takes paid personal/carer’s leave includes a day or part-day that is a public holiday in the place where the Doctor is based for work purposes, the Doctor is taken not to be on paid personal/carer’s leave on that public holiday.</p><p><strong>61.8</strong> Transfer of Accrued Personal/Carer’s Leave</p><p><strong>(a)</strong> Other than those Doctors described at subclause 61.9 below, a Doctor appointed to a Health Service:</p><p><strong>(i)</strong> up to five weeks after his or her termination of appointment at another Hospital or community health centre, not including any period of paid leave, or</p><p><strong>(ii)</strong> up to twenty-four months after his or her termination of employment at another Health Service or community health centre where the Doctor was absent from employment due to the birth or adoption of a child for the period consistent with Long Parental Leave (subclause 67.2(g)) (and provided the Doctor provides evidence that would satisfy a reasonable person as to the reason for the break in employment was consistent with this subclause),</p><p>must be credited up to 168 days of the Doctor’s accumulated personal/carer’s leave.</p><p><strong>(b)</strong> The accumulated personal/carer’s leave must be credited at the time of appointment.</p><p><strong>(c)</strong> A Certificate of Service will be acceptable evidence for the purpose of recognising accrued personal/carer’s leave. A certificate in the form set out in <a href="/eba/ebas/doctors-in-training/appendices/3-template-certificate-of-service.html">Appendix 3</a> will be acceptable.</p><p><strong>61.9</strong> Accrual Protection for Accredited Trainees</p><p><strong>(a)</strong> When a Doctor is employed as part of an accredited Specialist training program but not employed by a Health Service listed in <a href="/eba/ebas/doctors-in-training/appendices/1-list-of-employers-health-services.html">Appendix 1</a>, any personal/carer&#39;s leave accrued by the Doctor under this Agreement will be recognised when returning to the employ of a <a href="/eba/ebas/doctors-in-training/appendices/1-list-of-employers-health-services.html">Appendix 1</a> Health Service, provided that:</p><p><strong>(i)</strong> the break between periods of employment is not more than 2 months duration; and</p><p><strong>(ii)</strong> the personal/carer’s leave or service accrued with an employer other than a Health Service listed in <a href="/eba/ebas/doctors-in-training/appendices/1-list-of-employers-health-services.html">Appendix 1</a> is not recognised.</p><p><strong>(b)</strong> The Health Service may require a Doctor to produce a written statement from the previous Health Service that specifies the amount of accumulated personal/carer’s leave credited to the Doctor at the time of his or her termination of appointment.</p><p><strong>61.10</strong> Casual Doctors – Caring responsibilities</p><p><strong>(a)</strong> Casual Doctors are entitled to be unavailable to attend work or to leave work:</p><p><strong>(i)</strong> if they need to care for members of their immediate family or household who are sick or affected by personal injury and require care and support, or who require care due to an unexpected emergency, or the birth of a child; or</p><p><strong>(ii)</strong> upon the death in Australia of an immediate family or household member.</p><p><strong>(b)</strong> The Health Service and the Doctor will agree on the period for which the Doctor will be entitled to be unavailable to attend work. In the absence of agreement, the Doctor is entitled to be unavailable to attend work for up to two days per occasion. The Casual Doctor is not entitled to any payment for the period of non-attendance.</p><p><strong>(c)</strong> The Health Service will require the Casual Doctor to provide satisfactory evidence to support the taking of leave pursuant to this subclause 61.10.</p>',51)])])}const m=t(n,[["render",s]]);export{u as __pageData,m as default};
